#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BooleanLiteralEnum {
    True,
    False,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for BooleanLiteralEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        match transport_value_type(env, napi_val)? {
            ::napi::ValueType::Number => {
                if let Ok(kind_id) = u16::from_napi_value(env, napi_val) {
                    match kind_id {
                        127 => return Ok(Self::True), // "true"
                        128 => return Ok(Self::False), // "false"
                        _ => {}
                    }
                }
            }
            ::napi::ValueType::String => {
                match String::from_napi_value(env, napi_val)?.as_str() {
                    "true" => return Ok(Self::True),
                    "false" => return Ok(Self::False),
                    _ => {}
                }
            }
            ::napi::ValueType::Object => {
                let obj = ::napi::bindgen_prelude::Object::from_napi_value(env, napi_val)?;
                if let Some(kind_id) = obj.get::<u16>("$type")? {
                    match kind_id {
                        127 => return Ok(Self::True), // "true"
                        128 => return Ok(Self::False), // "false"
                        _ => {}
                    }
                }
                if let Some(text) = obj.get::<String>("$text")? {
                    match text.as_str() {
                        "true" => return Ok(Self::True),
                        "false" => return Ok(Self::False),
                        _ => {}
                    }
                }
                if obj.get::<::napi::bindgen_prelude::Object>("_true")?.is_some() { return Ok(Self::True); }
                if obj.get::<::napi::bindgen_prelude::Object>("_false")?.is_some() { return Ok(Self::False); }
            }
            _ => {}
        }
        Err(::napi::Error::from_reason("unknown enum payload for BooleanLiteralEnum"))
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for BooleanLiteralEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("BooleanLiteralEnum is receive-only"))
    }
}

impl ::std::fmt::Display for BooleanLiteralEnum {
    fn fmt(&self, f: &mut ::std::fmt::Formatter<'_>) -> ::std::fmt::Result {
        f.write_str(match self {
            Self::True => "true",
            Self::False => "false",
        })
    }
}

impl RenderableTransport for BooleanLiteralEnum {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        dest.write_str(match self {
            Self::True => "true",
            Self::False => "false",
        }).map_err(::askama::Error::from)
    }
}

